#include <iostream>
#include <memory>

int main() {
    std::weak_ptr<int> w;
    {
        auto s = std::make_shared<int>(5);
        w = s;
        std::cout << s.use_count() << "\n";
    }
    std::cout << w.expired() << "\n";
    auto locked = w.lock();
    std::cout << (locked ? "alive" : "dead") << "\n";
    return 0;
}
```

